#include<bits/stdc++.h>
using namespace std;
int main(void) {
    int n,ans=0,x[50000][10],i=0;
    cin>>n;
	for(int a=1;a<=3;a++){  
		for(int b=1;b<=3;b++){  
			for(int c=1;c<=3;c++){  
				for(int d=1;d<=3;d++){  
					for(int e=1;e<=3;e++){
						for(int f=1;f<=3;f++){  
							for(int g=1;g<=3;g++){
								for(int h=1;h<=3;h++){  
									for(int k=1;k<=3;k++){  
										for(int j=1;j<=3;j++){  
                                           	if(a+b+c+d+e+f+g+h+k+j==n) {  
												ans++,x[i][0]=a,x[i][1]=b,x[i][2]=c,x[i][3]=d;
												x[i][4]=e,x[i][5]=f,x[i][6]=g,x[i][7]=h,x[i][8]=k;
												x[i][9]=j,i++;
											}  
										}  
									}  
								}  
							}  
						}  
					}  
				}  
			}  
		}  
	}
	cout<<ans<<endl;
	for(int u=0;u<i;u++){
		for(int o=0;o<10;o++)cout<<x[u][o]<<" ";
		cout<<endl;
	}
    return false;
}
